mapper.select:


	and s.schedule_code like concat('%', #{scheduleCode}, '%')
	and s.work_order_id = #{workOrderId}
	and s.operation_id = #{operationId}
	and s.resource_id = #{resourceId}
	and s.status = #{status}

order by s.plan_start_time desc, s.schedule_id desc

select count(1) from mom_schedule
where resource_id = #{resourceId}
	and status in ('draft', 'released', 'running')
	and plan_start_time < #{planEndTime}
	and plan_end_time > #{planStartTime}
and schedule_id != #{scheduleId}

mapper.update:
update mom_schedule
schedule_code = #{scheduleCode}, work_order_id = #{workOrderId}, operation_id = #{operationId}, resource_id = #{resourceId}, plan_start_time = #{planStartTime}, plan_end_time = #{planEndTime}, plan_qty = #{planQty}, reported_qty = #{reportedQty}, status = #{status}, remark = #{remark}, update_by = #{updateBy}, update_time = CURRENT_TIMESTAMP
where schedule_id = #{scheduleId}

